import { getPublicKeyAsync, signAsync } from "@noble/ed25519";
import { mutate } from "@orderly.network/net";
import bs58 from "bs58";
import { z } from "zod";
import { getOrderlyEnvConfig } from "@/utils/environment";
import {
  storageKey,
  walletStorageKey,
  resolveWalletAddress,
} from "@/utils/storage";

const ADMIN_INFO_API_URL = "/v1/referral/admin_info";
const PUBLIC_ACCOUNT_API_URL = "/v1/public/account/";
const DEFAULT_ADMIN_GET_CACHE_TTL_MS = 1_000;
const VANGUARD_GET_CACHE_TTL_MS = 5_000;
export type AdminApiMethod = "GET" | "POST" | "PUT" | "DELETE";
export type MessageFactor = {
  url: string;
  method: AdminApiMethod;
  data?: Record<string, unknown> | null;
};

type OrderlyEnvelope<T = unknown> = {
  success?: boolean;
  message?: string;
  data?: T;
};

export type SignedAdminRequestInput = {
  endpoint: string;
  method?: AdminApiMethod;
  data?: Record<string, unknown> | null;
};

const signedAdminGetCache = new Map<
  string,
  { expiresAt: number; promise: Promise<unknown> }
>();
const adminAccountInfoCache = new Map<
  string,
  { expiresAt: number; promise: Promise<Record<string, unknown> | undefined> }
>();

export type AdminApiLoginValidation = {
  orderlyKey: string;
  orderlySecret: string;
  envConfig: ReturnType<typeof getOrderlyEnvConfig>;
  accountInfo?: Record<string, unknown>;
  brokerId?: string;
};

export type StoredAdminApiKey = {
  accountId?: string;
  key?: string;
  token?: string;
  secret?: string;
  brokerId?: string;
  env?: string;
  dexCreatorEnv?: string;
  expiresAt?: string;
  ownerWalletAddress?: string;
  walletAddress?: string;
  rememberSigningKey?: boolean;
};

type StoredAdminApiKeyReadOptions = {
  walletAddress?: string | null;
  skipWalletCheck?: boolean;
};

function sleep(ms: number) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

function normalizeWalletAddress(value?: string | null) {
  return value?.trim().toLowerCase() || undefined;
}

function readWalletAddressFromLoginContext() {
  if (typeof window === "undefined") return undefined;
  const wallet = resolveWalletAddress();
  const key = wallet
    ? walletStorageKey("orderlyLoginContext", wallet)
    : storageKey("orderlyLoginContext");
  const raw = window.localStorage.getItem(key);
  if (!raw) return undefined;
  try {
    const context = JSON.parse(raw) as {
      method?: string;
      walletAddress?: string;
    };
    if (context.method && context.method !== "wallet") return undefined;
    return normalizeWalletAddress(context.walletAddress);
  } catch {
    return undefined;
  }
}

function getApiKeyStorageKey(address?: string | null): string {
  const wallet = resolveWalletAddress(address);
  return wallet
    ? walletStorageKey("orderlyApiKey", wallet)
    : storageKey("orderlyApiKey");
}

function readRawStoredAdminApiKey(
  address?: string | null
): StoredAdminApiKey | null {
  if (typeof window === "undefined") return null;
  const raw = window.localStorage.getItem(getApiKeyStorageKey(address));
  if (!raw) return null;
  try {
    return JSON.parse(raw) as StoredAdminApiKey;
  } catch {
    return null;
  }
}

function getStoredKeyOwnerWallet(stored: StoredAdminApiKey) {
  return normalizeWalletAddress(
    stored.ownerWalletAddress || stored.walletAddress
  );
}

export function isStoredAdminApiKeyWalletCompatible(
  stored: StoredAdminApiKey,
  walletAddress?: string | null
): boolean {
  const ownerWallet = getStoredKeyOwnerWallet(stored);
  if (!ownerWallet) return true;
  const activeWallet =
    normalizeWalletAddress(walletAddress) ||
    readWalletAddressFromLoginContext();
  return Boolean(activeWallet && activeWallet === ownerWallet);
}

function isStoredAdminApiKeyCurrent(stored: StoredAdminApiKey) {
  if (stored.env && stored.env !== getOrderlyEnvConfig().env) return false;
  if (stored.expiresAt && new Date(stored.expiresAt) <= new Date())
    return false;
  return true;
}

function isRetriableAdminFailure(method: AdminApiMethod, response: unknown) {
  if (method !== "GET" && method !== "PUT") return false;
  const status =
    typeof response === "object" && response && "status" in response
      ? Number((response as { status?: unknown }).status)
      : undefined;
  const message =
    typeof response === "object" && response && "message" in response
      ? String((response as { message?: unknown }).message)
      : "";
  return (
    [429, 502, 503, 504].includes(status || 0) ||
    /\b(429|502|503|504)\b|service unavailable|gateway timeout|too many requests/i.test(
      message
    )
  );
}

function isCacheableVanguardGet(
  endpoint: string,
  method: AdminApiMethod,
  data?: Record<string, unknown> | null
) {
  if (method !== "GET" || data) return false;
  return (
    endpoint === "/v1/vanguard/summary" ||
    endpoint.startsWith("/v1/vanguard/invitees?") ||
    endpoint.startsWith("/v1/vanguard/revenue_share_history?")
  );
}

function clearSignedAdminGetCache() {
  signedAdminGetCache.clear();
}

function getSignedAdminGetCacheTtl(
  endpoint: string,
  method: AdminApiMethod,
  data?: Record<string, unknown> | null
) {
  if (method !== "GET" || data) return 0;
  if (isCacheableVanguardGet(endpoint, method, data))
    return VANGUARD_GET_CACHE_TTL_MS;
  return DEFAULT_ADMIN_GET_CACHE_TTL_MS;
}

export function readStoredAdminApiKey(
  options: StoredAdminApiKeyReadOptions = {}
): StoredAdminApiKey | null {
  const stored = readRawStoredAdminApiKey();
  if (!stored) return null;
  if (!isStoredAdminApiKeyCurrent(stored)) return null;
  if (
    !options.skipWalletCheck &&
    !isStoredAdminApiKeyWalletCompatible(stored, options.walletAddress)
  )
    return null;
  return stored;
}

export function hasCompleteStoredAdminApiKey(
  options: StoredAdminApiKeyReadOptions = {}
): boolean {
  const stored = readStoredAdminApiKey(options);
  if (!stored?.accountId || !(stored.key || stored.token) || !stored.secret)
    return false;
  return true;
}

export function clearStoredAdminApiKey(address?: string | null) {
  if (typeof window === "undefined") return;
  const storageKeys = new Set([
    getApiKeyStorageKey(address),
    storageKey("orderlyApiKey"),
  ]);
  for (let index = 0; index < window.localStorage.length; index += 1) {
    const key = window.localStorage.key(index);
    if (key?.startsWith("orderly-one:orderlyApiKey:")) {
      storageKeys.add(key);
    }
  }
  const storedKeys: StoredAdminApiKey[] = [];
  storageKeys.forEach(key => {
    const raw = window.localStorage.getItem(key);
    if (raw) {
      try {
        storedKeys.push(JSON.parse(raw) as StoredAdminApiKey);
      } catch {
        // Invalid stored key material is removed below.
      }
    }
    window.localStorage.removeItem(key);
  });
  adminAccountInfoCache.clear();
  clearSignedAdminGetCache();

  const storedAccountIds = Array.from(
    new Set(storedKeys.map(stored => stored.accountId).filter(Boolean))
  );
  if (storedAccountIds.length > 0) {
    const envConfig = getOrderlyEnvConfig();
    const envs = Array.from(
      new Set(
        [
          envConfig.env,
          envConfig.dexCreatorEnv,
          ...storedKeys.map(stored => stored.env),
          ...storedKeys.map(stored => stored.dexCreatorEnv),
        ].filter(Boolean)
      )
    );
    storedAccountIds.forEach(accountId => {
      envs.forEach(env =>
        window.localStorage.removeItem(`orderly-one:key:${accountId}:${env}`)
      );
    });
  } else {
    const keysToRemove: string[] = [];
    for (let index = 0; index < window.localStorage.length; index += 1) {
      const key = window.localStorage.key(index);
      if (key?.startsWith("orderly-one:key:")) keysToRemove.push(key);
    }
    keysToRemove.forEach(key => window.localStorage.removeItem(key));
  }

  window.dispatchEvent(new CustomEvent("authChanged"));
}

function removeDexCreatorStyleOrderlyKey(stored: StoredAdminApiKey) {
  if (!stored.accountId) return;
  const envConfig = getOrderlyEnvConfig();
  const envs = Array.from(
    new Set(
      [
        envConfig.env,
        envConfig.dexCreatorEnv,
        stored.env,
        stored.dexCreatorEnv,
      ].filter(Boolean)
    )
  );
  envs.forEach(env =>
    window.localStorage.removeItem(`orderly-one:key:${stored.accountId}:${env}`)
  );
}

export function clearUnrememberedStoredAdminApiKey(address?: string | null) {
  if (typeof window === "undefined") return;
  const storageKeys = new Set([
    getApiKeyStorageKey(address),
    storageKey("orderlyApiKey"),
  ]);

  storageKeys.forEach(key => {
    const raw = window.localStorage.getItem(key);
    if (!raw) return;
    try {
      const stored = JSON.parse(raw) as StoredAdminApiKey;
      if (
        stored.rememberSigningKey === false ||
        !isStoredAdminApiKeyCurrent(stored)
      ) {
        removeDexCreatorStyleOrderlyKey(stored);
        window.localStorage.removeItem(key);
      }
    } catch {
      window.localStorage.removeItem(key);
    }
  });

  adminAccountInfoCache.clear();
  clearSignedAdminGetCache();
}

export function shouldRequireOrderlyApiKey(
  profile?: {
    brokerId?: string;
    role?: string;
    graduated?: boolean;
    adminRegistered?: boolean;
  } | null
): boolean {
  const brokerId =
    profile?.brokerId ||
    (profile?.role === "ambassador" ? "ambassador" : undefined);
  if (!brokerId || brokerId === "demo") return false;
  if (profile?.role === "ambassador" || brokerId === "ambassador") return true;
  return Boolean(profile?.graduated && profile.adminRegistered);
}

function base64EncodeURL(byteArray: Uint8Array) {
  return btoa(
    Array.from(byteArray)
      .map(value => String.fromCharCode(value))
      .join("")
  )
    .replace(/\+/g, "-")
    .replace(/\//g, "_")
    .replace(/=/g, "");
}

export function saveDexCreatorStyleOrderlyKey(
  accountId: string,
  secretKey: string
) {
  if (typeof window === "undefined") return;
  const envConfig = getOrderlyEnvConfig();
  const normalizedSecret = secretKey.replace(/^ed25519:/i, "");
  const privateKeyBytes = bs58.decode(normalizedSecret);
  const encoded = base64EncodeURL(new Uint8Array(privateKeyBytes));
  const envKeys = new Set([envConfig.env, envConfig.dexCreatorEnv]);
  envKeys.forEach(env => {
    window.localStorage.setItem(`orderly-one:key:${accountId}:${env}`, encoded);
  });
}

function base64UrlSignature(signature: Uint8Array) {
  return btoa(
    Array.from(signature)
      .map(value => String.fromCharCode(value))
      .join("")
  )
    .replace(/\+/g, "-")
    .replace(/\//g, "_");
}

function buildSignText(message: MessageFactor, timestamp = Date.now()) {
  const orderlyTimestamp = timestamp.toString();
  let text = `${orderlyTimestamp}${message.method.toUpperCase()}${message.url}`;
  if (message.data && Object.keys(message.data).length)
    text += JSON.stringify(message.data);
  return { text, orderlyTimestamp };
}

function normalizeEd25519Value(value: string) {
  return value.trim().replace(/^ed25519:/i, "");
}

function extractEnvelopeData<T>(payload: unknown): T | undefined {
  if (!payload || typeof payload !== "object") return undefined;
  const envelope = payload as OrderlyEnvelope<T>;
  if (envelope.data !== undefined) return envelope.data;
  return payload as T;
}

function stringField(value: unknown) {
  return typeof value === "string" && value.trim() ? value.trim() : undefined;
}

async function getPublicKeyFromSecret(secret: string) {
  const privateKey = bs58.decode(normalizeEd25519Value(secret));
  return bs58.encode(await getPublicKeyAsync(privateKey));
}

async function signAdminPayload(message: MessageFactor, secret: string) {
  const privateKey = bs58.decode(normalizeEd25519Value(secret));
  const { text, orderlyTimestamp } = buildSignText(message);
  const signature = await signAsync(new TextEncoder().encode(text), privateKey);
  const publicKey = bs58.encode(await getPublicKeyAsync(privateKey));

  return {
    "orderly-key": `ed25519:${publicKey}`,
    "orderly-timestamp": orderlyTimestamp,
    "orderly-signature": base64UrlSignature(signature),
  };
}

async function adminRequestWithSecret<T>(input: {
  accountId: string;
  secret: string;
  endpoint: string;
  method?: AdminApiMethod;
  data?: Record<string, unknown> | null;
}) {
  const envConfig = getOrderlyEnvConfig();
  const method = input.method || "GET";
  const signature = await signAdminPayload(
    { method, url: input.endpoint, data: input.data },
    input.secret
  );
  return mutate(`${envConfig.apiBaseUrl}${input.endpoint}`, {
    method,
    headers: {
      ...signature,
      "orderly-account-id": input.accountId,
      ...(input.data ? { "Content-Type": "application/json" } : {}),
    },
    ...(input.data ? { body: JSON.stringify(input.data) } : {}),
  }) as Promise<T>;
}

export async function fetchAdminAccountInfo(input: {
  accountId: string;
  secret?: string;
}) {
  const secret = input.secret ?? readStoredAdminApiKey()?.secret;
  if (!secret)
    throw new Error("Stored admin API key is incomplete. Please log in again.");

  const endpoint = `${PUBLIC_ACCOUNT_API_URL}?account_id=${encodeURIComponent(input.accountId)}`;
  const cacheKey = `${getOrderlyEnvConfig().env}|${input.accountId}|${endpoint}`;
  if (!input.secret) {
    const cached = adminAccountInfoCache.get(cacheKey);
    if (cached && cached.expiresAt > Date.now()) return cached.promise;
  }

  const requestPromise = (async () => {
    const payload = await adminRequestWithSecret<
      OrderlyEnvelope<Record<string, unknown>> | Record<string, unknown>
    >({
      accountId: input.accountId,
      secret,
      endpoint,
    });
    return extractEnvelopeData<Record<string, unknown>>(payload);
  })();

  if (!input.secret) {
    adminAccountInfoCache.set(cacheKey, {
      expiresAt: Date.now() + DEFAULT_ADMIN_GET_CACHE_TTL_MS,
      promise: requestPromise,
    });
    requestPromise.catch(() => adminAccountInfoCache.delete(cacheKey));
  }

  return requestPromise;
}

export async function buildStoredAdminAuthHeaders(message: MessageFactor) {
  const stored = readStoredAdminApiKey();
  if (!stored?.accountId || !stored.secret) {
    throw new Error("Stored admin API key is incomplete. Please log in again.");
  }

  const signature = await signAdminPayload(message, stored.secret);
  return {
    ...signature,
    "orderly-account-id": stored.accountId,
  };
}

export async function validateAdminApiKeyLogin(input: {
  accountId: string;
  orderlyKey: string;
  orderlySecret: string;
}): Promise<AdminApiLoginValidation> {
  const envConfig = getOrderlyEnvConfig();
  const accountId = input.accountId.trim();
  const orderlyKey = normalizeEd25519Value(input.orderlyKey);
  const orderlySecret = normalizeEd25519Value(input.orderlySecret);
  const restoredKey = await getPublicKeyFromSecret(orderlySecret);
  if (restoredKey !== orderlyKey) {
    throw new Error(
      "The account information you entered is incorrect. Please verify and try logging in again."
    );
  }

  const response = await adminRequestWithSecret<OrderlyEnvelope>({
    accountId,
    secret: orderlySecret,
    endpoint: ADMIN_INFO_API_URL,
  });

  if (!response?.success)
    throw new Error(
      response?.message || "This account does not have admin permissions."
    );

  const accountInfo = await fetchAdminAccountInfo({
    accountId,
    secret: orderlySecret,
  }).catch(() => undefined);
  return {
    orderlyKey,
    orderlySecret,
    envConfig,
    accountInfo,
    brokerId: stringField(accountInfo?.broker_id),
  };
}

export class MissingApiKeyError extends Error {
  constructor() {
    super("An API key is needed to access dashboard data.");
    this.name = "MissingApiKeyError";
  }
}

export async function signedAdminRequest<T>(
  input: SignedAdminRequestInput,
  schema: z.ZodType<T>
): Promise<T>;
export async function signedAdminRequest<T>(
  input: SignedAdminRequestInput
): Promise<T>;
export async function signedAdminRequest<T>(
  input: SignedAdminRequestInput,
  schema?: z.ZodType<T>
): Promise<T> {
  if (typeof window === "undefined")
    throw new Error("Admin API is only available in the browser.");

  const stored = readStoredAdminApiKey();
  if (!stored) throw new MissingApiKeyError();

  if (!stored.accountId || !stored.secret) {
    throw new Error("Stored admin API key is incomplete. Please log in again.");
  }

  const accountIdForRequest = stored.accountId;
  const method = input.method || "GET";
  const envConfig = getOrderlyEnvConfig();

  if (method !== "GET") clearSignedAdminGetCache();

  const cacheTtl = getSignedAdminGetCacheTtl(
    input.endpoint,
    method,
    input.data
  );
  const cacheKey = `${envConfig.env}|${accountIdForRequest}|${method}|${input.endpoint}`;
  if (cacheTtl > 0) {
    const cached = signedAdminGetCache.get(cacheKey);
    if (cached && cached.expiresAt > Date.now())
      return cached.promise as Promise<T>;
  }

  const requestPromise = (async () => {
    const signature = await buildStoredAdminAuthHeaders({
      method,
      url: input.endpoint,
      data: input.data,
    });
    for (let attempt = 0; attempt < 3; attempt += 1) {
      const response = await mutate(
        `${envConfig.apiBaseUrl}${input.endpoint}`,
        {
          method,
          headers: {
            ...signature,
            "orderly-account-id": accountIdForRequest,
            ...(input.data ? { "Content-Type": "application/json" } : {}),
          },
          ...(input.data ? { body: JSON.stringify(input.data) } : {}),
        }
      );

      if (
        response &&
        typeof response === "object" &&
        "success" in response &&
        response.success === false
      ) {
        if (attempt < 2 && isRetriableAdminFailure(method, response)) {
          await sleep(300 * 2 ** attempt);
          continue;
        }
        throw new Error(response.message || "Admin API request failed.");
      }

      if (schema) return schema.parse(response) as T;
      return response as T;
    }

    throw new Error("Admin API request failed after retries.");
  })();

  if (cacheTtl > 0) {
    signedAdminGetCache.set(cacheKey, {
      expiresAt: Date.now() + cacheTtl,
      promise: requestPromise,
    });
    requestPromise.catch(() => signedAdminGetCache.delete(cacheKey));
  }

  return requestPromise;
}
