export type OrderlyEnv = "qa" | "staging" | "prod";

export interface OrderlyEnvConfig {
  env: OrderlyEnv;
  dexCreatorEnv: "qa" | "staging" | "mainnet";
  label: string;
  networkLabel: "qa" | "testnet" | "mainnet";
  apiBaseUrl: string;
  svUrl: string;
  dexBaseUrl: string;
  dexApiBaseUrl: string;
  adminBaseUrl: string;
  verifyingContract: string;
}

