const HOST_ENV_RULES: Array<{ env: OrderlyEnv; hosts: string[] }> = [
  {
    env: "qa",
    hosts: [
      "admin.qa.orderly-i.network",
      "admin.qa-aliyun.orderly-i.network",
      "admin.qa.orderly-e.network",
      "admin.qa-aliyun.orderly-e.network",
      "qa-admin.orderly.network",
    ],
  },
  {
    env: "staging",
    hosts: ["testnet-admin.orderly.network", "testnet-dex.orderly.network"],
  },
  { env: "prod", hosts: ["admin.orderly.network", "dex.orderly.network"] },
];

function normalizeEnv(value: unknown): OrderlyEnv | null {
  const normalized =
    typeof value === "string" ? value.trim().toLowerCase() : "";
  if (normalized === "mainnet" || normalized === "production") return "prod";
  if (normalized === "testnet") return "staging";
  if (normalized === "dev") return "qa";
  if (normalized === "qa" || normalized === "staging" || normalized === "prod")
    return normalized;
  return null;
}

function getHostname(): string {
  if (typeof window === "undefined") return "";
  return window.location.hostname.toLowerCase();
}

function isLocalHostname(hostname = getHostname()): boolean {
  return hostname === "localhost" || hostname === "127.0.0.1";
}

export function getOrderlyEnv(): OrderlyEnv {
  const envOverride = normalizeEnv(
    import.meta.env.VITE_DEPLOYMENT_ENV ||
      import.meta.env.VITE_ORDERLY_ENV ||
      import.meta.env.VITE_ENV
  );
  if (envOverride) return envOverride;

  const hostname = getHostname();
  if (isLocalHostname(hostname)) return "qa";

  const matchedRule = HOST_ENV_RULES.find(rule =>
    rule.hosts.includes(hostname)
  );
  return matchedRule?.env ?? "prod";
}

export function getOrderlyEnvConfig(
  env: OrderlyEnv = getOrderlyEnv()
): OrderlyEnvConfig {
  const base = ORDERLY_ENV_CONFIG[env];
  const localApiBase = import.meta.env.VITE_API_URL as string | undefined;
  if (localApiBase) {
    return { ...base, dexApiBaseUrl: localApiBase.replace(/\/+$/, "") };
  }
  return base;
}

export function getDistributorInviteUrl(
  code: string,
  env: OrderlyEnv = getOrderlyEnv()
): string {
  return `${
    ORDERLY_ENV_CONFIG[env].dexBaseUrl
  }/dex?distributor_code=${encodeURIComponent(code)}`;
}
